import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import Toast from '../components/Toast';

const getWorkflowIcon = (name = '') => {
  const lower = name.toLowerCase();
  if (lower.includes('mail') || lower.includes('gmail') || lower.includes('email')) {
    return 'mail';
  }
  if (lower.includes('sheet') || lower.includes('table') || lower.includes('excel')) {
    return 'table_chart';
  }
  if (lower.includes('slack') || lower.includes('discord') || lower.includes('chat')) {
    return 'chat';
  }
  if (lower.includes('database') || lower.includes('postgres') || lower.includes('sql') || lower.includes('db')) {
    return 'database';
  }
  if (lower.includes('webhook') || lower.includes('api') || lower.includes('http')) {
    return 'lan';
  }
  if (lower.includes('sync') || lower.includes('transfer')) {
    return 'sync';
  }
  return 'data_object';
};

export default function DashboardScreen() {
  const [workflows, setWorkflows] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [toasts, setToasts] = useState([]);

  const showToast = (message, type = 'success') => {
    const id = Date.now();
    setToasts((prev) => [...prev, { id, message, type }]);
  };

  const removeToast = (id) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  const fetchWorkflows = async () => {
    setIsLoading(true);
    try {
      const res = await axios.get('http://localhost:3001/api/workflows');
      // Handle either array response or { data: [...] } structure from backend
      const data = Array.isArray(res.data) ? res.data : (res.data?.data || []);
      setWorkflows(data);
    } catch (err) {
      console.error('Failed to fetch workflows', err);
      showToast('Failed to load workflows', 'error');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchWorkflows();
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this workflow?')) return;
    try {
      const res = await axios.delete(`http://localhost:3001/api/workflows/${id}`);
      if (res.data.success) {
        showToast('Workflow deleted successfully');
        fetchWorkflows();
      } else {
        throw new Error(res.data.error || 'Failed to delete workflow');
      }
    } catch (err) {
      const errorMsg = err.response?.data?.error || err.message || 'Something went wrong';
      showToast(`Error: ${errorMsg}`, 'error');
    }
  };

  const filteredWorkflows = workflows.filter((wf) =>
    wf.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="flex flex-col flex-1 overflow-hidden h-full">
      {/* TopNavBar */}
      <header className="sticky z-50 flex h-16 w-full items-center justify-between border-b border-outline-variant bg-surface px-margin-desktop">
        <div className="flex items-center gap-4">
          <img
            alt="FlowBuilder AI Logo"
            className="h-8 w-auto"
            src="data:image/png;base64,"
          />
          <span className="font-headline-md text-headline-md text-on-surface font-bold">
            FlowBuilder AI
          </span>
        </div>
        <div className="flex items-center gap-6">
          <nav className="flex gap-4">
            <Link
              className="text-on-surface-variant font-label-md hover:bg-surface-container-high transition-colors duration-200 px-3 py-2"
              to="/"
            >
              Chat
            </Link>
            <Link
              className="text-on-surface font-label-md bg-surface-container-high px-3 py-2 rounded"
              to="/dashboard"
            >
              Dashboard
            </Link>
          </nav>
          <div className="h-8 w-px bg-outline-variant"></div>
          <div className="flex items-center gap-2">
            <button className="p-2 text-on-surface-variant hover:bg-surface-container-high rounded transition-colors duration-200">
              <span className="material-symbols-outlined">notifications</span>
            </button>
            <button className="p-2 text-on-surface-variant hover:bg-surface-container-high rounded transition-colors duration-200">
              <span className="material-symbols-outlined">settings</span>
            </button>
          </div>
          <div className="h-8 w-8 rounded-full bg-surface-container-highest flex items-center justify-center overflow-hidden border border-outline-variant">
            <img
              className="h-full w-full object-cover"
              src="https://lh3.googleusercontent.com/aida-public/AB6AXuBkWlDbCQnjRS8tZsr_5JP_S3UqPb3KjB55ThqKgI9G17LBBvW9bA7xHncGQe-s2UtATJPfqBbITMBH_j3WXc9GcY5GjdtxlCAarjAuzgi5Q0oZvzyhOYhlYkYIbrs526etpTdW1FAzOKUaM5d44N8P6Iaq2ipUorVOBi2uA8zJNhXIvYOHpM_Qcgkyiu_ctlJt_9okTfAkd0MJHs0zgnTEyI4CwIxggOCvjylNKySUHoSaBRDnFWQybPnXuz72ncNwbQ7zN6TwAIg7"
              alt="User avatar"
            />
          </div>
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden h-full">
        {/* SideNavBar */}
        <aside className="w-[260px] h-full bg-surface-container-low border-r border-outline-variant flex flex-col py-6 px-4 gap-node-gap overflow-y-auto">
          <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-primary/10 rounded-lg">
              <span className="material-symbols-outlined text-primary">hub</span>
            </div>
            <div>
              <div className="font-headline-md text-[16px] leading-tight text-on-surface">Flow Engine</div>
              <div className="font-label-md text-[11px] text-on-surface-variant">v2.4.0 Active</div>
            </div>
          </div>

          <nav className="flex flex-1 flex-col gap-1">
            <a
              className="flex items-center gap-3 rounded-lg px-3 py-2 text-label-md font-label-md text-on-surface-variant transition-all hover:bg-surface-container-highest hover:text-on-surface"
              href="#"
              onClick={(e) => e.preventDefault()}
            >
              <span className="material-symbols-outlined">home</span>
              Home
            </a>
            <a
              className="flex items-center gap-3 rounded-lg bg-primary-container px-3 py-2 text-label-md font-label-md font-bold text-on-primary-container transition-all duration-150 active:translate-x-1"
              href="#"
              onClick={(e) => e.preventDefault()}
            >
              <span className="material-symbols-outlined">account_tree</span>
              Workflows
            </a>
            <a
              className="flex items-center gap-3 rounded-lg px-3 py-2 text-label-md font-label-md text-on-surface-variant transition-all hover:bg-surface-container-highest hover:text-on-surface"
              href="#"
              onClick={(e) => e.preventDefault()}
            >
              <span className="material-symbols-outlined">rocket_launch</span>
              Deployments
            </a>
            <a
              className="flex items-center gap-3 rounded-lg px-3 py-2 text-label-md font-label-md text-on-surface-variant transition-all hover:bg-surface-container-highest hover:text-on-surface"
              href="#"
              onClick={(e) => e.preventDefault()}
            >
              <span className="material-symbols-outlined">key</span>
              Credentials
            </a>
            <a
              className="flex items-center gap-3 rounded-lg px-3 py-2 text-label-md font-label-md text-on-surface-variant transition-all hover:bg-surface-container-highest hover:text-on-surface"
              href="#"
              onClick={(e) => e.preventDefault()}
            >
              <span className="material-symbols-outlined">description</span>
              Logs
            </a>
          </nav>

          <div className="flex flex-col gap-1 border-t border-outline-variant pt-4">
            <a
              href="http://localhost:5678"
              target="_blank"
              rel="noreferrer"
              className="flex items-center gap-3 rounded-lg px-3 py-2 text-label-md font-label-md text-on-surface-variant transition-all hover:bg-surface-container-highest hover:text-on-surface"
            >
              <span className="material-symbols-outlined">open_in_new</span>
              View in n8n
            </a>
            <a
              className="flex items-center gap-3 rounded-lg px-3 py-2 text-label-md font-label-md text-on-surface-variant transition-all hover:bg-surface-container-highest hover:text-on-surface"
              href="#"
              onClick={(e) => e.preventDefault()}
            >
              <span className="material-symbols-outlined">help</span>
              Help
            </a>
            <a
              className="flex items-center gap-3 rounded-lg px-3 py-2 text-label-md font-label-md text-on-surface-variant transition-all hover:bg-surface-container-highest hover:text-on-surface"
              href="#"
              onClick={(e) => e.preventDefault()}
            >
              <span className="material-symbols-outlined">logout</span>
              Logout
            </a>
          </div>
        </aside>

        {/* Main Content Area */}
        <main className="canvas-bg relative flex-1 overflow-y-auto">
          {/* Header/Actions Bar */}
          <div className="sticky top-0 z-10 flex flex-col justify-between gap-4 bg-background/80 px-margin-desktop py-8 backdrop-blur-md md:flex-row md:items-center">
            <div>
              <h1 className="font-headline-lg text-headline-lg text-on-surface font-bold">
                Workflow Directory
              </h1>
              <p className="font-body-md text-on-surface-variant">
                Manage and monitor your automated logic pipelines.
              </p>
            </div>
            <div className="flex items-center gap-4">
              <div className="group relative">
                <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-outline group-focus-within:text-primary">
                  search
                </span>
                <input
                  className="w-64 rounded-lg border border-outline-variant bg-[#0f0f0f] py-2.5 pl-10 pr-4 text-label-md font-label-md text-on-surface transition-all focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
                  placeholder="Search workflows..."
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
              <Link
                to="/"
                className="flex items-center gap-2 rounded-lg bg-[#3b82f6] px-5 py-2.5 text-label-md font-label-md font-bold text-white shadow-lg shadow-blue-500/20 transition-all hover:bg-[#2563eb] active:scale-95"
              >
                <span className="material-symbols-outlined">add</span>
                New Workflow
              </Link>
            </div>
          </div>

          {/* Dashboard Grid */}
          <div className="grid grid-cols-1 gap-gutter px-margin-desktop pb-12 md:grid-cols-2 xl:grid-cols-3">
            {isLoading && (
              <p className="col-span-full text-center py-10 text-on-surface-variant">
                Loading workflows...
              </p>
            )}
            {!isLoading && filteredWorkflows.length === 0 && (
              <p className="col-span-full text-center py-10 text-on-surface-variant italic">
                {searchQuery ? 'No workflows match your search query.' : 'No workflows built yet.'}
              </p>
            )}

            {!isLoading &&
              filteredWorkflows.map((wf) => {
                const icon = getWorkflowIcon(wf.name);
                return (
                  <div
                    key={wf.id}
                    className="glass-card group flex flex-col gap-4 rounded-xl p-6 transition-all border border-[#2e2e2e] bg-[#1a1a1a]/85 shadow-lg hover:border-primary"
                  >
                    <div className="flex justify-between items-start">
                      <div className="flex h-12 w-12 items-center justify-center rounded-lg border border-outline-variant bg-surface-container-high transition-colors group-hover:border-primary">
                        <span className="material-symbols-outlined text-primary">
                          {icon}
                        </span>
                      </div>
                      {wf.active ? (
                        <div className="flex items-center gap-2 border border-green-500/20 bg-green-500/10 px-3 py-1 rounded-full text-[11px] font-bold text-green-400">
                          <span className="h-2 w-2 rounded-full bg-green-400"></span>
                          Deployed
                        </div>
                      ) : (
                        <div className="flex items-center gap-2 border border-outline-variant bg-surface-container-high/40 px-3 py-1 rounded-full text-[11px] font-bold text-outline">
                          <span className="h-2 w-2 rounded-full bg-outline"></span>
                          Inactive
                        </div>
                      )}
                    </div>
                    <div>
                      <h3 className="font-headline-md text-[18px] text-on-surface font-bold truncate">
                        {wf.name}
                      </h3>
                      <p className="font-label-md text-[12px] text-on-surface-variant">
                        ID: {wf.id}
                      </p>
                    </div>
                    <div className="flex items-center gap-6 border-y border-outline-variant/30 py-2">
                      <div className="flex flex-col">
                        <span className="font-label-md text-[10px] uppercase text-outline">Nodes</span>
                        <span className="font-headline-md text-[16px] text-on-surface">
                          {wf.nodes ? wf.nodes.length : 0}
                        </span>
                      </div>
                      <div className="flex flex-col">
                        <span className="font-label-md text-[10px] uppercase text-outline">Updated</span>
                        <span className="font-headline-md text-[16px] text-on-surface truncate max-w-[150px]">
                          {wf.updatedAt
                            ? new Date(wf.updatedAt).toLocaleDateString('en-US', {
                                month: 'short',
                                day: 'numeric',
                              })
                            : 'N/A'}
                        </span>
                      </div>
                    </div>
                    <div className="mt-2 flex items-center gap-2">
                      <a
                        href="http://localhost:5678"
                        target="_blank"
                        rel="noreferrer"
                        className="flex flex-1 items-center justify-center gap-2 rounded-lg bg-surface-container-highest px-3 py-2 text-label-md font-label-md text-on-surface transition-colors hover:bg-primary/20 hover:text-primary border border-transparent hover:border-outline-variant"
                      >
                        <span className="material-symbols-outlined text-[18px]">open_in_new</span>{' '}
                        n8n
                      </a>
                      <Link
                        to={`/workflow/${wf.id}`}
                        className="flex flex-1 items-center justify-center gap-2 rounded-lg bg-surface-container-highest px-3 py-2 text-label-md font-label-md text-on-surface transition-colors hover:bg-primary/20 hover:text-primary border border-transparent hover:border-outline-variant"
                      >
                        <span className="material-symbols-outlined text-[18px]">edit</span> Edit
                      </Link>
                      <button
                        onClick={() => handleDelete(wf.id)}
                        className="flex h-10 w-10 items-center justify-center rounded-lg bg-surface-container-highest text-on-surface-variant transition-colors hover:bg-error-container/20 hover:text-error border border-transparent hover:border-outline-variant"
                      >
                        <span className="material-symbols-outlined text-[18px]">delete</span>
                      </button>
                    </div>
                  </div>
                );
              })}
          </div>
        </main>
      </div>

      {/* Render Toasts */}
      <div className="fixed bottom-6 right-6 z-[9999] flex flex-col gap-2 pointer-events-none">
        {toasts.map((toast) => (
          <Toast
            key={toast.id}
            message={toast.message}
            type={toast.type}
            onClose={() => removeToast(toast.id)}
          />
        ))}
      </div>
    </div>
  );
}
